#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        char name1[21], name2[21];
        int p1, p2;
        scanf("%s %s", name1, name2);
        scanf("%d %d", &p1, &p2);
        if (p1 > p2) {
            printf("%s\n", name1);
        } else if (p2 > p1) {
            printf("%s\n", name2);
        } else {
            printf("**equal**\n");
        }
    }
    return 0;
}

