import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine();
        if (line == null || line.isEmpty()) return;
        int T = Integer.parseInt(line.trim());
        StringBuilder sb = new StringBuilder();
        for (int t = 0; t < T; t++) {
            String[] names = br.readLine().trim().split(" ");
            String name1 = names[0];
            String name2 = names[1];
            String[] perc = br.readLine().trim().split(" ");
            int p1 = Integer.parseInt(perc[0]);
            int p2 = Integer.parseInt(perc[1]);
            if (p1 > p2) sb.append(name1);
            else if (p2 > p1) sb.append(name2);
            else sb.append("**equal**");
            if (t != T - 1) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

