import sys

def main():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    T = int(data[0])
    out = []
    idx = 1
    for _ in range(T):
        name1, name2 = data[idx].split()
        idx += 1
        p1, p2 = map(int, data[idx].split())
        idx += 1
        if p1 > p2:
            out.append(name1)
        elif p2 > p1:
            out.append(name2)
        else:
            out.append("**equal**")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    main()

